import{_ as r,o as l,c as e,ai as i}from"./chunks/framework.D_fGE_7X.js";const d=JSON.parse('{"title":"吳彥東 (Yen-Tung Wu) | wuc656","description":"","frontmatter":{},"headers":[],"relativePath":"gemini.md","filePath":"gemini.md","lastUpdated":1772511278000}'),o={name:"gemini.md"};function n(t,a,s,c,g,h){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="吳彥東-yen-tung-wu-wuc656" tabindex="-1">吳彥東 (Yen-Tung Wu) | wuc656 <a class="header-anchor" href="#吳彥東-yen-tung-wu-wuc656" aria-label="Permalink to “吳彥東 (Yen-Tung Wu) | wuc656”">​</a></h1><blockquote><p><strong>全端軟體工程師 | Minecraft 伺服器創辦人 | 數位技術探索者</strong></p></blockquote><hr><h2 id="👤-基本資料" tabindex="-1">👤 基本資料 <a class="header-anchor" href="#👤-基本資料" aria-label="Permalink to “👤 基本資料”">​</a></h2><ul><li><strong>姓名</strong>：吳彥東</li><li><strong>暱稱</strong>：東東 / wuc656</li><li><strong>生日</strong>：2000 年 12 月 22 日</li><li><strong>出生地</strong>：台灣苗栗市</li><li><strong>居住地</strong>：台中市（僑泰高中時期）/ 高雄市（高科大時期）</li><li><strong>語言</strong>：繁體中文 (台灣)、English</li></ul><hr><h2 id="💻-專業背景-professional-background" tabindex="-1">💻 專業背景 (Professional Background) <a class="header-anchor" href="#💻-專業背景-professional-background" aria-label="Permalink to “💻 專業背景 (Professional Background)”">​</a></h2><h3 id="🚀-現職與工作經驗" tabindex="-1">🚀 現職與工作經驗 <a class="header-anchor" href="#🚀-現職與工作經驗" aria-label="Permalink to “🚀 現職與工作經驗”">​</a></h3><ul><li><strong>中程資訊顧問有限公司 (CMIS)</strong> | 軟體工程師 (2024/03/18 – 至今) <ul><li>負責將傳統 <strong>Delphi 2009</strong> 開發的營建工程管理系統 (ERP) 轉型為現代化網頁版。</li><li>負責維護「CMIS 整合桌面資訊系統」與「CMIS 銷售前置分析系統」。</li></ul></li></ul><h3 id="🛠️-技術棧-technical-skills" tabindex="-1">🛠️ 技術棧 (Technical Skills) <a class="header-anchor" href="#🛠️-技術棧-technical-skills" aria-label="Permalink to “🛠️ 技術棧 (Technical Skills)”">​</a></h3><ul><li><strong>後端開發</strong>：Golang (Echo, XORM)、Delphi 2009</li><li><strong>前端開發</strong>：Vue.js, Vite, Axios, PrimeVue, TailwindCSS, MasterCSS</li><li><strong>系統運維</strong>：電腦組裝、系統重灌、網路優化、Windows API 封裝 (Go winres)</li><li><strong>工具/套件維護</strong>：積極參與開源社群，維護如 <code>vite-plugin-vue-layouts</code>、<code>secure-ls</code> 等 NPM 套件。</li></ul><hr><h2 id="🎓-教育經歷-education" tabindex="-1">🎓 教育經歷 (Education) <a class="header-anchor" href="#🎓-教育經歷-education" aria-label="Permalink to “🎓 教育經歷 (Education)”">​</a></h2><ul><li><strong>國立高雄科技大學 (NKUST)</strong> | 資訊工程系 (2019 – 2023)</li><li><strong>台中市私立僑泰高級中學</strong> | 資訊科 (2016 – 2019)</li><li><strong>大道國民中學</strong> (2013 – 2016)</li><li><strong>山陽國民小學</strong> ( – 2013)</li></ul><h3 id="🎖️-重要事蹟" tabindex="-1">🎖️ 重要事蹟 <a class="header-anchor" href="#🎖️-重要事蹟" aria-label="Permalink to “🎖️ 重要事蹟”">​</a></h3><ul><li><strong>2016年</strong>：國中教育會考取得 3A2B (A++, A+, A, B++, B+) 優異成績。</li><li><strong>2015-2016年</strong>：與學校老師合作，擔任大道國中畢業微電影製作。</li><li><strong>軍旅生涯</strong>：2023 年 9 月入伍，同年 12 月結訓（4個月軍事訓練役）。</li></ul><hr><h2 id="🎮-遊戲社群與創作成就" tabindex="-1">🎮 遊戲社群與創作成就 <a class="header-anchor" href="#🎮-遊戲社群與創作成就" aria-label="Permalink to “🎮 遊戲社群與創作成就”">​</a></h2><h3 id="🏰-東東的創世神伺服器-dds-wuc656-com" tabindex="-1">🏰 東東的創世神伺服器 (DDS / wuc656.com) <a class="header-anchor" href="#🏰-東東的創世神伺服器-dds-wuc656-com" aria-label="Permalink to “🏰 東東的創世神伺服器 (DDS / wuc656.com)”">​</a></h3><p>自 2013 年（1.5.2 版本）起創立並營運 Minecraft 伺服器，展現強大的社群經營與伺服器架設能力：</p><ul><li><strong>版本演進</strong>：從 1.5.2 營運至 1.12.2、1.19.4 等多個版本。</li><li><strong>經營特點</strong>：自費投入獎學金升級光纖網路提供玩家優質環境；設有 24 小時生存、槍械副本、住宅區、公會系統。</li><li><strong>跨平台經營</strong>：建立專屬網站、Discord 頻道及 Facebook 萬人社團，並實施「優質玩家驗證制度」。</li></ul><h3 id="🕹️-個人興趣" tabindex="-1">🕹️ 個人興趣 <a class="header-anchor" href="#🕹️-個人興趣" aria-label="Permalink to “🕹️ 個人興趣”">​</a></h3><ul><li><strong>遊戲愛好</strong>：星球：重啟、崩壞：星穹鐵道、英雄聯盟 (LOL)。</li><li><strong>技術探索</strong>：從遊戲需求出發研究電腦知識，具備深厚的電腦硬體維護與優化實力。</li></ul><hr><h2 id="🌐-連結與社群-social-media" tabindex="-1">🌐 連結與社群 (Social Media) <a class="header-anchor" href="#🌐-連結與社群-social-media" aria-label="Permalink to “🌐 連結與社群 (Social Media)”">​</a></h2><ul><li><strong>GitHub</strong>: <a href="https://github.com/wuc656" target="_blank" rel="noreferrer">wuc656</a></li><li><strong>個人網站/部落格</strong>: <a href="https://www.wuc656.com/" target="_blank" rel="noreferrer">wuc656.com</a> / <a href="https://wuc656.github.io/" target="_blank" rel="noreferrer">GitHub Pages</a></li><li><strong>NPM Profile</strong>: <a href="https://www.npmjs.com/~wuc656" target="_blank" rel="noreferrer">~wuc656</a></li><li><strong>Email</strong>: <a href="mailto:wuc656@gmail.com" target="_blank" rel="noreferrer">wuc656@gmail.com</a></li><li><strong>社群媒體</strong>: Facebook 粉絲團、Instagram、Twitch、Youtube、Twitter(X)</li></ul><hr><h2 id="💡-個人特質" tabindex="-1">💡 個人特質 <a class="header-anchor" href="#💡-個人特質" aria-label="Permalink to “💡 個人特質”">​</a></h2><blockquote><p><strong>「自幼因遊戲踏入電腦領域，將興趣轉化為專業職能。」</strong> 吳彥東具備極強的自學能力與實踐精神，無論是伺服器管理或是 ERP 系統的現代化轉型，皆展現出解決複雜問題的韌性。</p></blockquote>',29)])])}const m=r(o,[["render",n]]);export{d as __pageData,m as default};
